CREATE PROCEDURE [dbo].[TR_DINHMUC_SON3_MAUSON_INSERT]
(
	@id uniqueidentifier,	@mamau nvarchar(50),	@stt int,	@buoc nvarchar(200),	@mact nvarchar(200),	@tenct nvarchar(200),	@soluong float,	@matson nvarchar(50),	@t_sort int,	@makhuvuc nvarchar(50),	@macongdoan nvarchar(50),	@stt_buoc nvarchar(5),	@donhot nvarchar(200),	@thoigiankho nvarchar(200),	@cachthuchien nvarchar(200),	@tonghonhop float,	@ngaytao datetime,	@nguoitao nvarchar(50),	@ngaysua datetime,	@nguoisua nvarchar(50)
)
AS
BEGIN
	SELECT @makhuvuc = department FROM trtb_m_op WHERE c_op = @macongdoan
	IF @makhuvuc IS NULL
		SET @makhuvuc = 'SON'
	INSERT INTO tr_dinhmuc_son3_mauson
	(
		id,		mamau,		stt,		buoc,		mact,		tenct,		soluong,		matson,		t_sort,		makhuvuc,		macongdoan,		stt_buoc,		donhot,		thoigiankho,		cachthuchien,		tonghonhop,		ngaytao,		nguoitao,		ngaysua,		nguoisua
	)
	VALUES
	(
		@id,		@mamau,		@stt,		@buoc,		@mact,		@tenct,		@soluong,		@matson,		@t_sort,		@makhuvuc,		@macongdoan,		@stt_buoc,		@donhot,		@thoigiankho,		@cachthuchien,		@tonghonhop,		@ngaytao,		@nguoitao,		@ngaysua,		@nguoisua
	)
END
